array_filter(
				$theplus_options,
				function ( $widget ) use ( $all_widgets ) {
					$normalized = str_replace( '-', '_', $widget );
					return in_array( $normalized, $all_widgets );
				}
			)

wp_remote_get(
			$url,
			array(
				'timeout'    => self::TIMEOUT,
				'user-agent' => 'Elementor-MCP/' . ELEMENTOR_MCP_VERSION . ' (WordPress/' . get_bloginfo( 'version' ) . ')',
				'headers'    => array(
					'Accept' => 'application/json',
				),
			)
		)

array_map(function ($item) {
            return [
                'content_description' => wp_kses_post((string) ($item['content_description'] ?? '')),
                'icon_style'          => sanitize_key((string) ($item['icon_style'] ?? 'None')),
                'link'                => ['url' => esc_url_raw((string) ($item['link'] ?? ''))],
                '_id'                 => substr(bin2hex(random_bytes(4)), 0, 7),
            ];
        }, $input['list_items'])

array_map(
			function ( $val ) use ( $replace ) {
				$val = str_replace( array( 'theplus-' ), array( '' ), $val );
				return ( array_key_exists( $val, $replace ) ? $replace[ $val ] : $val );
			},
			$this->transient_widgets
		)

wp_send_json_error([
				'message' => __('Invalid permission. Only administrators can perform this action.', 'tpebl')
			], 403)

